import React, { useState, useEffect } from 'react';
import axios from 'axios';

function AdminDashboard() {
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);

  // 1. Fetch all project requests from Backend
  useEffect(() => {
    fetchRequests();
  }, []);

  const fetchRequests = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
      setLoading(false);
    } catch (err) {
      console.error("Error fetching data:", err);
      setLoading(false);
    }
  };

  // 2. Function to Update Progress or Status
  const handleUpdate = async (id, updatedData) => {
    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, updatedData);
      alert("Project Updated Successfully!");
      fetchRequests(); // Refresh data
    } catch (err) {
      alert("Error updating project.");
    }
  };

  // 3. Function to Mark Payment as Full (Advance = Total)
  const markAsFullPaid = async (id, totalAmount) => {
    if (window.confirm("Are you sure this project is fully paid?")) {
      try {
        await axios.put(`http://localhost:5000/api/update-status/${id}`, {
          advancePaid: totalAmount,
          paymentStatus: 'Paid'
        });
        alert("Payment Marked as Fully Paid!");
        fetchRequests();
      } catch (err) {
        alert("Error updating payment.");
      }
    }
  };

  if (loading) return <div className="text-center py-5">Loading Dashboard...</div>;

  return (
    <div className="container py-5">
      <h2 className="fw-bold mb-4">Admin <span className="text-primary">Control Panel</span></h2>
      <p className="text-muted mb-5">Manage your clients, project progress, and payments efficiently.</p>

      <div className="row g-4">
        {requests.map((project) => {
          // LOGIC: Calculate Remaining Balance
          const remainingAmount = project.totalBudget - project.advancePaid;

          return (
            <div key={project._id} className="col-12">
              <div className="card shadow-sm border-0 rounded-4 p-4 mb-2">
                <div className="row align-items-center">
                  
                  {/* Client Info */}
                  <div className="col-md-3 border-end">
                    <h5 className="fw-bold mb-0">{project.fullName}</h5>
                    <small className="text-primary fw-bold text-uppercase">{project.serviceType}</small>
                    <p className="small text-muted mb-0 mt-1">{project.email}</p>
                  </div>

                  {/* Progress Section */}
                  <div className="col-md-3 text-center px-4">
                    <div className="d-flex justify-content-between mb-1">
                      <small className="fw-bold">Progress</small>
                      <small className="fw-bold text-primary">{project.progress}%</small>
                    </div>
                    <div className="progress rounded-pill shadow-sm" style={{ height: '12px' }}>
                      <div 
                        className="progress-bar progress-bar-striped progress-bar-animated bg-primary" 
                        style={{ width: `${project.progress}%` }}
                      ></div>
                    </div>
                    {/* Progress Slider to update manually */}
                    <input 
                      type="range" className="form-range mt-2" min="0" max="100" 
                      defaultValue={project.progress} 
                      onMouseUp={(e) => handleUpdate(project._id, { progress: e.target.value })}
                    />
                  </div>

                  {/* Payment Calculation Section */}
                  <div className="col-md-3 text-center border-start border-end">
                    {remainingAmount > 0 ? (
                      <div>
                        <small className="text-muted d-block">Remaining Balance</small>
                        <h4 className="text-danger fw-bold mb-0">₹{remainingAmount}</h4>
                        <small className="text-muted">Total: ₹{project.totalBudget}</small>
                      </div>
                    ) : (
                      <div className="py-2">
                        <span className="badge bg-success p-2 px-3 rounded-pill">
                          ✅ FULLY PAID
                        </span>
                        <div className="small mt-1 text-muted">Total Received: ₹{project.totalBudget}</div>
                      </div>
                    )}
                  </div>

                  {/* Actions Section */}
                  <div className="col-md-3 text-end">
                    {remainingAmount > 0 ? (
                      <button 
                        className="btn btn-outline-success btn-sm fw-bold px-4 rounded-pill shadow-sm"
                        onClick={() => markAsFullPaid(project._id, project.totalBudget)}
                      >
                        Mark Full Paid
                      </button>
                    ) : (
                      <button className="btn btn-light btn-sm text-muted disabled rounded-pill border">
                        Payment Settled
                      </button>
                    )}
                    <button 
                      className="btn btn-danger btn-sm rounded-circle ms-2"
                      onClick={async () => {
                         if(window.confirm("Delete this request?")) {
                           await axios.delete(`http://localhost:5000/api/delete-request/${project._id}`);
                           fetchRequests();
                         }
                      }}
                    >
                      <i className="fas fa-trash"></i>
                    </button>
                  </div>

                </div>
              </div>
            </div>
          );
        })}
      </div>

      {requests.length === 0 && (
        <div className="text-center py-5">
          <h4 className="text-muted">No active project requests found.</h4>
        </div>
      )}
    </div>
  );
}

export default AdminDashboard;
